import React, { useState } from 'react';
import axios from 'axios';

function Review({ review, bookId, api_url, onReviewDeleted, onReviewEdited }) {
  const [isEditing, setIsEditing] = useState(false);
  const [editedName, setEditedName] = useState(review.name);
  const [editedComment, setEditedComment] = useState(review.comment);
  const [editedRating, setEditedRating] = useState(review.rating);
  const [isDeleting, setIsDeleting] = useState(false);

  const handleDelete = async () => {
    const userConfirmed = window.confirm('Are you sure you want to delete this review?');
    if (!userConfirmed) return;

    setIsDeleting(true);
    try {
      await axios.delete(`${api_url}/books/${bookId}/reviews/${review.id}`);
      onReviewDeleted(review.id);
    } catch (error) {
      console.error('Error deleting review:', error);
    } finally {
      setIsDeleting(false);
    }
  };

  const handleEdit = async () => {
    try {
      const response = await axios.put(`${api_url}/books/${bookId}/reviews/${review.id}`, {
        name: editedName,
        comment: editedComment,
        rating: parseInt(editedRating),
      });
      onReviewEdited(response.data);
      setIsEditing(false);
    } catch (error) {
      console.error('Error editing review:', error);
    }
  };

  if (isEditing) {
    return (
      <div className="bg-gray-50 rounded-xl p-6 shadow-md">
        <input
          type="text"
          value={editedName}
          onChange={(e) => setEditedName(e.target.value)}
          className="w-full mb-2 p-2 border border-gray-300 rounded"
        />
        <textarea
          value={editedComment}
          onChange={(e) => setEditedComment(e.target.value)}
          className="w-full mb-2 p-2 border border-gray-300 rounded"
          rows="3"
        />
        <select
          value={editedRating}
          onChange={(e) => setEditedRating(e.target.value)}
          className="w-full p-2 border border-gray-300 rounded"
        >
          {[1, 2, 3, 4, 5].map(star => <option key={star} value={star}>{star} Star{star > 1 && 's'}</option>)}
        </select>
        <div className="flex justify-end mt-4 space-x-2">
          <button
            onClick={handleEdit}
            className="bg-green-500 text-white px-4 py-2 rounded-full hover:bg-green-600 transition-colors"
          >
            Save
          </button>
          <button
            onClick={() => setIsEditing(false)}
            className="bg-gray-500 text-white px-4 py-2 rounded-full hover:bg-gray-600 transition-colors"
          >
            Cancel
          </button>
        </div>
      </div>
    );
  }

  const getReviewGradient = (rating) => {
    if (rating >= 4.5) return 'from-emerald-50 to-teal-50 border-emerald-200';
    if (rating >= 4.0) return 'from-blue-50 to-indigo-50 border-blue-200';
    if (rating >= 3.5) return 'from-purple-50 to-pink-50 border-purple-200';
    return 'from-orange-50 to-red-50 border-orange-200';
  };

  const getReviewIconColor = (rating) => {
    if (rating >= 4.5) return 'text-emerald-500';
    if (rating >= 4.0) return 'text-blue-500';
    if (rating >= 3.5) return 'text-purple-500';
    return 'text-orange-500';
  };

  return (
    <div className={`bg-gradient-to-r ${getReviewGradient(review.rating)} rounded-2xl p-8 border-2 hover:shadow-lg transition-all duration-200 transform hover:-translate-y-1`}>
      <div className="flex items-start justify-between mb-6">
        <div className="flex items-center space-x-4">
          <div className={`w-12 h-12 rounded-full bg-white shadow-md flex items-center justify-center ${getReviewIconColor(review.rating)}`}>
            <span className="text-xl font-bold">{review.name.charAt(0).toUpperCase()}</span>
          </div>
          <div>
            <h4 className="text-xl font-semibold text-gray-800">{review.name}</h4>
            <div className="flex items-center mt-1">
              <div className="flex items-center space-x-1">
                {[...Array(5)].map((_, i) => (
                  <span 
                    key={i} 
                    className={`text-lg ${
                      i < Math.floor(review.rating) 
                        ? 'text-yellow-400' 
                        : i < review.rating 
                        ? 'text-yellow-300' 
                        : 'text-gray-200'
                    }`}
                  >
                    ⭐
                  </span>
                ))}
              </div>
              <span className="ml-2 text-lg font-bold text-gray-700">{review.rating}</span>
            </div>
          </div>
        </div>

        <div className="flex space-x-2">
          <button
            onClick={() => setIsEditing(true)}
            className="inline-flex items-center px-4 py-2 bg-white bg-opacity-80 text-indigo-600 rounded-xl font-semibold hover:bg-opacity-100 hover:shadow-md transition-all duration-200 transform hover:scale-105 border border-indigo-200"
          >
            <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
            </svg>
            Edit
          </button>
          <button
            onClick={handleDelete}
            disabled={isDeleting}
            className="inline-flex items-center px-4 py-2 bg-white bg-opacity-80 text-red-600 rounded-xl font-semibold hover:bg-opacity-100 hover:shadow-md transition-all duration-200 transform hover:scale-105 border border-red-200 disabled:opacity-50"
          >
            <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
            </svg>
            {isDeleting ? 'Deleting...' : 'Delete'}
          </button>
        </div>
      </div>

      <div className="bg-white bg-opacity-60 rounded-xl p-6">
        <p className="text-gray-700 leading-relaxed text-lg font-medium">
          "{review.comment}"
        </p>
      </div>
    </div>
  );
}

export default Review;
